def iter_nodes_by_kind(graph: nx.DiGraph, kind: str) -> list[tuple[str, dict[str, Any]]]:
    return [
        (node_id, attrs)
        for node_id, attrs in graph.nodes(data=True)
        if str(attrs.get("node_kind") or attrs.get("kind") or "") == kind
    ]

